1	use crate::models::auth::Claims;
2	use jsonwebtoken::{decode, DecodingKey, Validation};
3	use rocket::http::Status;
4	use rocket::request::{FromRequest, Outcome, Request};
5	
6	#[derive(Debug, Clone)]
7	pub struct AuthenticatedUser {
8	    pub user_id: String,
9	    pub username: String,
10	    pub role: String,
11	    pub session_id: String,
12	    pub permissions: Vec<String>,
13	}
14	
15	#[rocket::async_trait]
16	impl<'r> FromRequest<'r> for AuthenticatedUser {
17	    type Error = &'static str;
18	
19	    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Self::Error> {
20	        let jwt_secret = match std::env::var("JWT_SECRET") {
21	            Ok(s) if s.len() >= 32 => s,
22	            _ => {
23	                log::error!("JWT_SECRET not set or too short — refusing auth");
24	                return Outcome::Error((Status::ServiceUnavailable, "Server misconfigured"));
25	            }
26	        };
27	
28	        let auth_header = request.headers().get_one("Authorization");
29	
30	        match auth_header {
31	            Some(header) if header.starts_with("Bearer ") => {
32	                let token = &header[7..];
33	                match decode::<Claims>(
34	                    token,
35	                    &DecodingKey::from_secret(jwt_secret.as_bytes()),
36	                    &Validation::default(),
37	                ) {
38	                    Ok(token_data) => {
39	                        let claims = token_data.claims;
40	
41	                        // --- FAIL-CLOSED: DB pool must be available ---
42	                        let pool = match request.rocket().state::<crate::DbPool>() {
43	                            Some(p) => p,
44	                            None => {
45	                                log::error!("DB pool unavailable — denying request (fail-closed)");
46	                                return Outcome::Error((
47	                                    Status::ServiceUnavailable,
48	                                    "Service unavailable",
49	                                ));
50	                            }
51	                        };
52	
53	                        // --- FAIL-CLOSED: session check must succeed ---
54	                        let session_check = sqlx::query_as::<_, (bool, chrono::NaiveDateTime)>(
55	                            "SELECT is_active, expires_at FROM sessions WHERE id = ? AND user_id = ?",
56	                        )
57	                        .bind(&claims.session_id)
58	                        .bind(&claims.sub)
59	                        .fetch_optional(pool)
60	                        .await;
61	
62	                        match session_check {
63	                            Ok(Some((is_active, expires_at))) => {
64	                                let now = chrono::Utc::now().naive_utc();
65	                                if !is_active || now > expires_at {
66	                                    return Outcome::Error((
67	                                        Status::Unauthorized,
68	                                        "Session expired",
69	                                    ));
70	                                }
71	                                // Refresh idle timeout
72	                                let new_expiry = now
73	                                    + chrono::Duration::minutes(
74	                                        crate::models::SESSION_IDLE_TIMEOUT_MINUTES,
75	                                    );
76	                                let _ = sqlx::query(
77	                                    "UPDATE sessions SET last_activity = ?, expires_at = ? WHERE id = ?",
78	                                )
79	                                .bind(now)
80	                                .bind(new_expiry)
81	                                .bind(&claims.session_id)
82	                                .execute(pool)
83	                                .await;
84	                            }
85	                            Ok(None) => {
86	                                return Outcome::Error((
87	                                    Status::Unauthorized,
88	                                    "Session not found",
89	                                ));
90	                            }
91	                            Err(e) => {
92	                                // FAIL-CLOSED: DB error → deny
93	                                log::error!(
94	                                    "Session DB check failed for user {}: {} — denying (fail-closed)",
95	                                    claims.sub, e
96	                                );
97	                                return Outcome::Error((
98	                                    Status::ServiceUnavailable,
99	                                    "Session verification unavailable",
100	                                ));
101	                            }
102	                        }
103	
104	                        // --- Load permissions from role_permissions join ---
105	                        let permissions: Vec<String> = sqlx::query_scalar::<_, String>(
106	                            "SELECT p.name FROM permissions p \
107	                             INNER JOIN role_permissions rp ON rp.permission_id = p.id \
108	                             INNER JOIN roles r ON r.id = rp.role_id \
109	                             WHERE r.name = ?",
110	                        )
111	                        .bind(&claims.role)
112	                        .fetch_all(pool)
113	                        .await
114	                        .unwrap_or_default();
115	
116	                        Outcome::Success(AuthenticatedUser {
117	                            user_id: claims.sub,
118	                            username: claims.username,
119	                            role: claims.role,
120	                            session_id: claims.session_id,
121	                            permissions,
122	                        })
123	                    }
124	                    Err(_) => Outcome::Error((Status::Unauthorized, "Invalid token")),
125	                }
126	            }
127	            _ => Outcome::Error((Status::Unauthorized, "Missing authorization header")),
128	        }
129	    }
130	}
131	
132	impl AuthenticatedUser {
133	    /// Check if user has a specific permission
134	    pub fn has_permission(&self, perm: &str) -> bool {
135	        self.permissions.iter().any(|p| p == perm)
136	    }
137	
138	    /// Require a permission or return 403
139	    pub fn require_permission(&self, perm: &str) -> Result<(), rocket::http::Status> {
140	        if self.has_permission(perm) {
141	            Ok(())
142	        } else {
143	            Err(rocket::http::Status::Forbidden)
144	        }
145	    }
146	
147	    /// Require any of the given permissions, or return 403.
148	    pub fn require_any_permission(&self, perms: &[&str]) -> Result<(), rocket::http::Status> {
149	        if perms.iter().any(|p| self.has_permission(p)) {
150	            Ok(())
151	        } else {
152	            Err(rocket::http::Status::Forbidden)
153	        }
154	    }
155	
156	    /// True if this user has staff-level or admin-level permissions.
157	    pub fn is_privileged(&self) -> bool {
158	        self.has_permission("users.list") || self.has_permission("admin.dashboard")
159	    }
160	
161	    /// Require privileged access (staff or admin) or return 403.
162	    pub fn require_privileged(&self) -> Result<(), rocket::http::Status> {
163	        if self.is_privileged() {
164	            Ok(())
165	        } else {
166	            Err(rocket::http::Status::Forbidden)
167	        }
168	    }
169	
170	    /// Require that the user is either the owner of the resource or privileged.
171	    pub fn require_owner_or_privileged(&self, resource_owner_id: &str) -> Result<(), rocket::http::Status> {
172	        if self.user_id == resource_owner_id || self.is_privileged() {
173	            Ok(())
174	        } else {
175	            Err(rocket::http::Status::Forbidden)
176	        }
177	    }
178	}
