9	#[get("/")]
10	pub async fn list_users(pool: &State<DbPool>, user: AuthenticatedUser) -> Result<Json<Vec<UserResponse>>, Status> {
11	    user.require_privileged()?;
12	
13	    let rows = sqlx::query_as::<_, (String, String, String, String, String, Option<String>, String, bool, Option<String>, bool, bool, bool, bool, Option<chrono::NaiveDateTime>)>(
14	        "SELECT id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, notify_submissions, notify_orders, notify_reviews, notify_cases, created_at FROM users WHERE soft_deleted_at IS NULL ORDER BY created_at DESC"
15	    )
16	    .fetch_all(pool.inner())
17	    .await
18	    .map_err(|e| { log::error!("list_users: select users query failed: {}", e); Status::InternalServerError })?;
19	
20	    let users: Vec<UserResponse> = rows.into_iter().map(|(id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, ns, no, nr, nc, created_at)| {
21	        UserResponse { id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, notify_submissions: ns, notify_orders: no, notify_reviews: nr, notify_cases: nc, created_at }
22	    }).collect();
23	
24	    Ok(Json(users))
25	}
