27	#[get("/<user_id>")]
28	pub async fn get_user(pool: &State<DbPool>, auth: AuthenticatedUser, user_id: String) -> Result<Json<UserResponse>, Status> {
29	    if auth.user_id != user_id && !auth.is_privileged() {
30	        return Err(Status::Forbidden);
31	    }
32	
33	    let row = sqlx::query_as::<_, (String, String, String, String, String, Option<String>, String, bool, Option<String>, bool, bool, bool, bool, Option<chrono::NaiveDateTime>)>(
34	        "SELECT id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, notify_submissions, notify_orders, notify_reviews, notify_cases, created_at FROM users WHERE id = ?"
35	    )
36	    .bind(&user_id)
37	    .fetch_optional(pool.inner())
38	    .await
39	    .map_err(|e| { log::error!("get_user: select user query failed: {}", e); Status::InternalServerError })?;
40	
41	    match row {
42	        Some((id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, ns, no, nr, nc, created_at)) => {
43	            Ok(Json(UserResponse { id, username, email, first_name, last_name, contact_info, role, is_active, invoice_title, notify_submissions: ns, notify_orders: no, notify_reviews: nr, notify_cases: nc, created_at }))
44	        }
45	        None => Err(Status::NotFound),
46	    }
47	}
