49	#[put("/profile", data = "<req>")]
50	pub async fn update_profile(pool: &State<DbPool>, auth: AuthenticatedUser, req: Json<UpdateProfileRequest>) -> Result<Status, Status> {
51	    if let Some(ref first_name) = req.first_name {
52	        sqlx::query("UPDATE users SET first_name = ?, updated_at = NOW() WHERE id = ?")
53	            .bind(first_name).bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_profile: update first_name failed: {}", e); Status::InternalServerError })?;
54	    }
55	    if let Some(ref last_name) = req.last_name {
56	        sqlx::query("UPDATE users SET last_name = ?, updated_at = NOW() WHERE id = ?")
57	            .bind(last_name).bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_profile: update last_name failed: {}", e); Status::InternalServerError })?;
58	    }
59	    if let Some(ref username) = req.username {
60	        let exists = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM users WHERE username = ? AND id != ?")
61	            .bind(username).bind(&auth.user_id).fetch_one(pool.inner()).await.map_err(|e| { log::error!("update_profile: username duplicate check failed: {}", e); Status::InternalServerError })?;
62	        if exists > 0 { return Err(Status::Conflict); }
63	        sqlx::query("UPDATE users SET username = ?, updated_at = NOW() WHERE id = ?")
64	            .bind(username).bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_profile: update username failed: {}", e); Status::InternalServerError })?;
65	    }
66	    if let Some(ref contact_info) = req.contact_info {
67	        sqlx::query("UPDATE users SET contact_info = ?, updated_at = NOW() WHERE id = ?")
68	            .bind(contact_info).bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_profile: update contact_info failed: {}", e); Status::InternalServerError })?;
69	    }
70	    if let Some(ref invoice_title) = req.invoice_title {
71	        sqlx::query("UPDATE users SET invoice_title = ?, updated_at = NOW() WHERE id = ?")
72	            .bind(invoice_title).bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_profile: update invoice_title failed: {}", e); Status::InternalServerError })?;
73	    }
74	    Ok(Status::Ok)
75	}
