98	#[put("/<user_id>/role", data = "<req>")]
99	pub async fn update_user_role(pool: &State<DbPool>, auth: AuthenticatedUser, user_id: String, req: Json<UpdateUserRoleRequest>) -> Result<Status, Status> {
100	    auth.require_permission("users.role_change")?;
101	    let valid_roles = ["student", "instructor", "academic_staff", "administrator"];
102	    if !valid_roles.contains(&req.role.as_str()) {
103	        return Err(Status::BadRequest);
104	    }
105	
106	    // Get old role for audit
107	    let old_role = sqlx::query_scalar::<_, String>("SELECT role FROM users WHERE id = ?")
108	        .bind(&user_id).fetch_optional(pool.inner()).await.map_err(|e| { log::error!("update_user_role: select role query failed: {}", e); Status::InternalServerError })?;
109	
110	    sqlx::query("UPDATE users SET role = ?, updated_at = NOW() WHERE id = ?")
111	        .bind(&req.role).bind(&user_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_user_role: update role failed: {}", e); Status::InternalServerError })?;
112	
113	    // Audit log for permission change
114	    let details = format!("Role changed from '{}' to '{}'", old_role.unwrap_or_default(), req.role);
115	    let _ = sqlx::query("INSERT INTO audit_log (id, user_id, action, target_type, target_id, details, created_at) VALUES (?, ?, 'role_changed', 'user', ?, ?, NOW())")
116	        .bind(Uuid::new_v4().to_string()).bind(&auth.user_id).bind(&user_id).bind(&details)
117	        .execute(pool.inner()).await;
118	
119	    Ok(Status::Ok)
120	}
