122	#[delete("/<user_id>")]
123	pub async fn deactivate_user(pool: &State<DbPool>, auth: AuthenticatedUser, user_id: String) -> Result<Status, Status> {
124	    // Only administrators can deactivate user accounts
125	    if auth.role != "administrator" {
126	        return Err(Status::Forbidden);
127	    }
128	    auth.require_permission("users.manage")?;
129	    sqlx::query("UPDATE users SET is_active = false, updated_at = NOW() WHERE id = ?")
130	        .bind(&user_id).execute(pool.inner()).await.map_err(|e| { log::error!("deactivate_user: update is_active failed: {}", e); Status::InternalServerError })?;
131	
132	    let _ = sqlx::query("INSERT INTO audit_log (id, user_id, action, target_type, target_id, details, created_at) VALUES (?, ?, 'user_deactivated', 'user', ?, 'User deactivated by admin', NOW())")
133	        .bind(Uuid::new_v4().to_string()).bind(&auth.user_id).bind(&user_id)
134	        .execute(pool.inner()).await;
135	
136	    Ok(Status::NoContent)
137	}
