158	#[post("/addresses", data = "<req>")]
159	pub async fn create_address(pool: &State<DbPool>, auth: AuthenticatedUser, req: Json<CreateAddressRequest>) -> Result<Json<UserAddress>, Status> {
160	    if req.state.len() != 2 {
161	        return Err(Status::BadRequest);
162	    }
163	
164	    let id = Uuid::new_v4().to_string();
165	    let is_default = req.is_default.unwrap_or(false);
166	
167	    // If setting as default, unset others
168	    if is_default {
169	        sqlx::query("UPDATE user_addresses SET is_default = false WHERE user_id = ?")
170	            .bind(&auth.user_id).execute(pool.inner()).await.map_err(|e| { log::error!("create_address: unset default addresses failed: {}", e); Status::InternalServerError })?;
171	    }
172	
173	    sqlx::query(
174	        "INSERT INTO user_addresses (id, user_id, label, street_line1, street_line2, city, state, zip_code, is_default) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)"
175	    )
176	    .bind(&id).bind(&auth.user_id).bind(&req.label).bind(&req.street_line1).bind(&req.street_line2)
177	    .bind(&req.city).bind(&req.state).bind(&req.zip_code).bind(is_default)
178	    .execute(pool.inner()).await.map_err(|e| { log::error!("create_address: insert address failed: {}", e); Status::InternalServerError })?;
179	
180	    Ok(Json(UserAddress {
181	        id, user_id: auth.user_id, label: req.label.clone(), street_line1: req.street_line1.clone(),
182	        street_line2: req.street_line2.clone(), city: req.city.clone(), state: req.state.clone(),
183	        zip_code: req.zip_code.clone(), is_default,
184	    }))
185	}
