1	use crate::middleware::AuthenticatedUser;
2	use crate::models::case::*;
3	use crate::models;
4	use crate::DbPool;
5	use rocket::http::Status;
6	use rocket::serde::json::Json;
7	use rocket::State;
8	use uuid::Uuid;
9	
10	// Use a reduced query to stay within sqlx 16-field tuple limit
11	const CASE_SELECT: &str = "SELECT id, order_id, reporter_id, assigned_to, case_type, subject, description, status, priority, submitted_at, first_response_at, first_response_due, resolution_target, resolved_at, closed_at, created_at FROM after_sales_cases";
12	
13	type CaseRow = (String, String, String, Option<String>, String, String, String, String, String, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>);
14	
15	fn row_to_case(r: CaseRow) -> AfterSalesCase {
16	    AfterSalesCase {
17	        id: r.0, order_id: r.1, reporter_id: r.2, assigned_to: r.3,
18	        case_type: r.4, subject: r.5, description: r.6, status: r.7, priority: r.8,
19	        submitted_at: r.9, first_response_at: r.10, first_response_due: r.11,
20	        resolution_target: r.12, resolved_at: r.13, closed_at: r.14,
21	        created_at: r.15, updated_at: None,
22	    }
23	}
24	
25	fn compute_sla(case: &AfterSalesCase) -> CaseWithSla {
26	    let now = chrono::Utc::now().naive_utc();
27	
28	    let first_response_overdue = match (case.first_response_at, case.first_response_due) {
29	        (None, Some(due)) => now > due,
30	        _ => false,
31	    };
32	
33	    let resolution_overdue = match (case.resolved_at, case.resolution_target) {
34	        (None, Some(target)) => now > target,
35	        _ => false,
36	    };
37	
38	    let hours_until_first_response = match (case.first_response_at, case.first_response_due) {
39	        (None, Some(due)) => Some((due - now).num_minutes() as f64 / 60.0),
40	        _ => None,
41	    };
42	
43	    let hours_until_resolution = match (case.resolved_at, case.resolution_target) {
44	        (None, Some(target)) => Some((target - now).num_minutes() as f64 / 60.0),
45	        _ => None,
46	    };
47	
48	    CaseWithSla {
49	        case: case.clone(),
50	        first_response_overdue,
51	        resolution_overdue,
52	        hours_until_first_response,
53	        hours_until_resolution,
54	    }
55	}
