58	pub async fn create_case(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<CreateCaseRequest>) -> Result<Json<CaseWithSla>, Status> {
59	    let valid_types = ["return", "refund", "exchange"];
60	    if !valid_types.contains(&req.case_type.as_str()) {
61	        return Err(Status::BadRequest);
62	    }
63	
64	    // Verify the referenced order exists and belongs to the requesting user
65	    let order_owner = sqlx::query_scalar::<_, String>("SELECT user_id FROM orders WHERE id = ?")
66	        .bind(&req.order_id)
67	        .fetch_optional(pool.inner())
68	        .await
69	        .map_err(|e| { log::error!("create_case: select order owner failed: {}", e); Status::InternalServerError })?;
70	
71	    match order_owner {
72	        Some(owner_id) => {
73	            if owner_id != user.user_id && !user.is_privileged() {
74	                return Err(Status::Forbidden);
75	            }
76	        }
77	        None => return Err(Status::NotFound),
78	    }
79	
80	    let id = Uuid::new_v4().to_string();
81	    let priority = req.priority.clone().unwrap_or_else(|| "medium".to_string());
82	    let now = chrono::Utc::now().naive_utc();
83	    let first_response_due = models::add_business_days(now, 2);
84	    let resolution_target = models::add_business_days(now, 7);
85	
86	    sqlx::query(
87	        "INSERT INTO after_sales_cases (id, order_id, reporter_id, case_type, subject, description, status, priority, submitted_at, first_response_due, resolution_target, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, 'submitted', ?, ?, ?, ?, NOW(), NOW())"
88	    )
89	    .bind(&id).bind(&req.order_id).bind(&user.user_id).bind(&req.case_type)
90	    .bind(&req.subject).bind(&req.description).bind(&priority)
91	    .bind(&now).bind(&first_response_due).bind(&resolution_target)
92	    .execute(pool.inner()).await.map_err(|e| { log::error!("create_case: insert case failed: {}", e); Status::InternalServerError })?;
93	
94	    let case = AfterSalesCase {
95	        id, order_id: req.order_id.clone(), reporter_id: user.user_id,
96	        assigned_to: None, case_type: req.case_type.clone(), subject: req.subject.clone(),
97	        description: req.description.clone(), status: "submitted".to_string(), priority,
98	        submitted_at: Some(now), first_response_at: None, first_response_due: Some(first_response_due),
99	        resolution_target: Some(resolution_target), resolved_at: None, closed_at: None,
100	        created_at: Some(now), updated_at: Some(now),
101	    };
102	
103	    Ok(Json(compute_sla(&case)))
104	}
