146	pub async fn update_case_status(pool: &State<DbPool>, user: AuthenticatedUser, case_id: String, req: Json<UpdateCaseStatusRequest>) -> Result<Status, Status> {
147	    user.require_privileged()?;
148	
149	    let current = sqlx::query_scalar::<_, String>("SELECT status FROM after_sales_cases WHERE id = ?")
150	        .bind(&case_id).fetch_optional(pool.inner()).await.map_err(|e| { log::error!("update_case_status: select current status failed: {}", e); Status::InternalServerError })?;
151	
152	    match current {
153	        Some(cur) => {
154	            if !models::valid_case_transition(&cur, &req.status) {
155	                return Err(Status::BadRequest);
156	            }
157	
158	            sqlx::query("UPDATE after_sales_cases SET status = ?, updated_at = NOW() WHERE id = ?")
159	                .bind(&req.status).bind(&case_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_case_status: update status failed: {}", e); Status::InternalServerError })?;
160	
161	            if cur == "submitted" && req.status == "in_review" {
162	                sqlx::query("UPDATE after_sales_cases SET first_response_at = COALESCE(first_response_at, NOW()) WHERE id = ?")
163	                    .bind(&case_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_case_status: update first_response_at failed: {}", e); Status::InternalServerError })?;
164	            }
165	            if req.status == "approved" || req.status == "denied" {
166	                sqlx::query("UPDATE after_sales_cases SET resolved_at = NOW() WHERE id = ?")
167	                    .bind(&case_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_case_status: update resolved_at failed: {}", e); Status::InternalServerError })?;
168	            }
169	            if req.status == "closed" {
170	                sqlx::query("UPDATE after_sales_cases SET closed_at = NOW() WHERE id = ?")
171	                    .bind(&case_id).execute(pool.inner()).await.map_err(|e| { log::error!("update_case_status: update closed_at failed: {}", e); Status::InternalServerError })?;
172	            }
173	
174	            Ok(Status::Ok)
175	        }
176	        None => Err(Status::NotFound),
177	    }
178	}
