86	/// Run SQL migrations — fail-fast on errors (panics on critical failures).
87	async fn run_migrations(pool: &DbPool) {
88	    let migrations = include_str!("migrations/001_initial.sql");
89	    for statement in migrations.split(';') {
90	        let trimmed = statement.trim();
91	        if !trimmed.is_empty() {
92	            match sqlx::query(trimmed).execute(pool).await {
93	                Ok(_) => {}
94	                Err(e) => {
95	                    let err_str = e.to_string();
96	                    // "already exists" is expected on re-runs — safe to skip
97	                    if err_str.contains("already exists") || err_str.contains("Duplicate") {
98	                        log::debug!("Migration skip (idempotent): {}", err_str);
99	                    } else {
100	                        panic!("FATAL: Migration failed — {}", err_str);
101	                    }
102	                }
103	            }
104	        }
105	    }
106	    log::info!("Database migrations completed");
107	
108	    let seed = include_str!("migrations/002_seed.sql");
109	    for statement in seed.split(';') {
110	        let trimmed = statement.trim();
111	        if !trimmed.is_empty() {
112	            match sqlx::query(trimmed).execute(pool).await {
113	                Ok(_) => {}
114	                Err(e) => {
115	                    let err_str = e.to_string();
116	                    if err_str.contains("Duplicate") {
117	                        log::debug!("Seed skip (idempotent): {}", err_str);
118	                    } else {
119	                        panic!("FATAL: Seed data failed — {}", err_str);
120	                    }
121	                }
122	            }
123	        }
124	    }
125	    log::info!("Seed data applied");
126	
127	    // If ADMIN_PASSWORD is set, re-hash and apply to all seeded accounts
128	    if let Ok(admin_pass) = std::env::var("ADMIN_PASSWORD") {
129	        match bcrypt::hash(&admin_pass, bcrypt::DEFAULT_COST) {
130	            Ok(hash) => {
131	                let _ = sqlx::query(
132	                    "UPDATE users SET password_hash = ? WHERE username IN ('admin', 'moderator', 'host', 'clerk', 'member')"
133	                )
134	                .bind(&hash)
135	                .execute(pool)
136	                .await;
137	                log::info!("Seeded user credentials updated from ADMIN_PASSWORD");
138	            }
139	            Err(e) => log::warn!("Failed to hash ADMIN_PASSWORD: {}", e),
140	        }
141	    }
142	}
