290	pub async fn use_reset_token(pool: &State<DbPool>, req: Json<UseResetTokenRequest>) -> Result<Status, Status> {
291	    let row = sqlx::query_as::<_, (String, String, bool, chrono::NaiveDateTime)>(
292	        "SELECT id, user_id, used, expires_at FROM password_reset_tokens WHERE token = ?"
293	    )
294	    .bind(&req.token)
295	    .fetch_optional(pool.inner())
296	    .await
297	    .map_err(|e| { log::error!("use_reset_token: token query failed: {}", e); Status::InternalServerError })?;
298	
299	    match row {
300	        Some((token_id, user_id, used, expires_at)) => {
301	            if used {
302	                return Err(Status::Gone);
303	            }
304	            if Utc::now().naive_utc() > expires_at {
305	                return Err(Status::Gone);
306	            }
307	
308	            let new_password = req.new_password.clone();
309	            let new_hash = tokio::task::spawn_blocking(move || {
310	                hash(&new_password, DEFAULT_COST)
311	            }).await.map_err(|e| { log::error!("use_reset_token: bcrypt hash spawn failed: {}", e); Status::InternalServerError })?.map_err(|e| { log::error!("use_reset_token: bcrypt hash failed: {}", e); Status::InternalServerError })?;
312	
313	            sqlx::query("UPDATE users SET password_hash = ?, updated_at = NOW() WHERE id = ?")
314	                .bind(&new_hash)
315	                .bind(&user_id)
316	                .execute(pool.inner())
317	                .await
318	                .map_err(|e| { log::error!("use_reset_token: update password_hash failed: {}", e); Status::InternalServerError })?;
319	
320	            sqlx::query("UPDATE password_reset_tokens SET used = true WHERE id = ?")
321	                .bind(&token_id)
322	                .execute(pool.inner())
323	                .await
324	                .map_err(|e| { log::error!("use_reset_token: update token used flag failed: {}", e); Status::InternalServerError })?;
325	
326	            log_audit(pool.inner(), Some(&user_id), "password_reset_used", Some("user"), Some(&user_id), None).await;
327	            Ok(Status::Ok)
328	        }
329	        None => Err(Status::NotFound),
330	    }
331	}
