40	/// Generates SEO metadata from title and summary deterministically
41	pub fn generate_seo(title: &str, summary: Option<&str>) -> (String, String, String) {
42	    let meta_title = if title.len() > 120 {
43	        title[..120].to_string()
44	    } else {
45	        title.to_string()
46	    };
47	
48	    let meta_description = match summary {
49	        Some(s) if s.len() > 155 => s[..155].to_string(),
50	        Some(s) => s.to_string(),
51	        None if title.len() > 155 => title[..155].to_string(),
52	        None => title.to_string(),
53	    };
54	
55	    let slug_val = slug::slugify(title);
56	
57	    (meta_title, meta_description, slug_val)
58	}
