60	/// Validates content metadata lengths
61	pub fn validate_metadata(title: &str, summary: Option<&str>, tags: Option<&str>, keywords: Option<&str>) -> Result<(), String> {
62	    if title.len() > 120 {
63	        return Err("Title must be 120 characters or fewer".to_string());
64	    }
65	    if let Some(s) = summary {
66	        if s.len() > 500 {
67	            return Err("Summary must be 500 characters or fewer".to_string());
68	        }
69	    }
70	    if let Some(t) = tags {
71	        if t.len() > 1000 {
72	            return Err("Tags field exceeds maximum length of 1000 characters".to_string());
73	        }
74	        for tag in t.split(',') {
75	            if tag.trim().len() > 50 {
76	                return Err("Individual tag must be 50 characters or fewer".to_string());
77	            }
78	        }
79	    }
80	    if let Some(k) = keywords {
81	        if k.len() > 1000 {
82	            return Err("Keywords field exceeds maximum length of 1000 characters".to_string());
83	        }
84	        for kw in k.split(',') {
85	            if kw.trim().len() > 50 {
86	                return Err("Individual keyword must be 50 characters or fewer".to_string());
87	            }
88	        }
89	    }
90	    Ok(())
91	}
