125	/// Add N business days (Mon–Fri) to a datetime, skipping weekends.
126	pub fn add_business_days(from: chrono::NaiveDateTime, days: u32) -> chrono::NaiveDateTime {
127	    use chrono::Datelike;
128	    let mut result = from;
129	    let mut remaining = days;
130	    while remaining > 0 {
131	        result += chrono::Duration::days(1);
132	        match result.weekday() {
133	            chrono::Weekday::Sat | chrono::Weekday::Sun => {}
134	            _ => remaining -= 1,
135	        }
136	    }
137	    result
138	}
