1	use gloo_net::http::Request;
2	use gloo_storage::{LocalStorage, Storage};
3	use serde::{de::DeserializeOwned, Serialize};
4	
5	/// Derive the backend URL from the current browser location so the frontend
6	/// works on both localhost and LAN deployments (same host, backend port 8000).
7	fn backend_url() -> String {
8	    web_sys::window()
9	        .and_then(|w| w.location().hostname().ok())
10	        .map(|host| {
11	            let protocol = web_sys::window()
12	                .and_then(|w| w.location().protocol().ok())
13	                .unwrap_or_else(|| "http:".to_string());
14	            format!("{}//{}:8000", protocol, host)
15	        })
16	        .unwrap_or_else(|| "http://localhost:8000".to_string())
17	}
18	
19	fn auth_header() -> Option<String> {
20	    LocalStorage::get::<String>("auth_token")
21	        .ok()
22	        .map(|t| format!("Bearer {}", t))
23	}
24	
25	pub async fn get<T: DeserializeOwned>(path: &str) -> Result<T, String> {
26	    let url = format!("{}{}", backend_url(), path);
27	    let mut req = Request::get(&url);
28	
29	    if let Some(token) = auth_header() {
30	        req = req.header("Authorization", &token);
31	    }
32	
33	    let resp = req.send().await.map_err(|e| e.to_string())?;
34	
35	    if resp.ok() {
36	        resp.json::<T>().await.map_err(|e| e.to_string())
37	    } else {
38	        Err(format!("Request failed with status: {}", resp.status()))
39	    }
40	}
41	
42	pub async fn post<T: DeserializeOwned, B: Serialize>(path: &str, body: &B) -> Result<T, String> {
43	    let url = format!("{}{}", backend_url(), path);
44	    let mut req = Request::post(&url)
45	        .header("Content-Type", "application/json");
46	
47	    if let Some(token) = auth_header() {
48	        req = req.header("Authorization", &token);
49	    }
50	
51	    let body_str = serde_json::to_string(body).map_err(|e| e.to_string())?;
52	    let resp = req.body(body_str).unwrap().send().await.map_err(|e| e.to_string())?;
53	
54	    if resp.ok() {
55	        resp.json::<T>().await.map_err(|e| e.to_string())
56	    } else {
57	        Err(format!("Request failed with status: {}", resp.status()))
58	    }
59	}
60	
