62	pub async fn post_empty<B: Serialize>(path: &str, body: &B) -> Result<(), String> {
63	    let url = format!("{}{}", backend_url(), path);
64	    let mut req = Request::post(&url)
65	        .header("Content-Type", "application/json");
66	
67	    if let Some(token) = auth_header() {
68	        req = req.header("Authorization", &token);
69	    }
70	
71	    let body_str = serde_json::to_string(body).map_err(|e| e.to_string())?;
72	    let resp = req.body(body_str).unwrap().send().await.map_err(|e| e.to_string())?;
73	
74	    if resp.ok() { Ok(()) } else { Err(format!("Request failed with status: {}", resp.status())) }
75	}
