112	/// Render a visible text watermark onto an image (PNG or JPG).
113	/// Decodes the image, draws semi-transparent text diagonally across the pixels,
114	/// then re-encodes in the original format.
115	fn render_visible_image_watermark(img_bytes: &[u8], watermark: &str, output_format: image::ImageOutputFormat) -> Vec<u8> {
116	    use image::{GenericImageView, Rgba, RgbaImage};
117	
118	    let img = match image::load_from_memory(img_bytes) {
119	        Ok(i) => i,
120	        Err(_) => return img_bytes.to_vec(), // fallback: return original if decode fails
121	    };
122	
123	    let (w, h) = img.dimensions();
124	    let mut overlay = img.to_rgba8();
125	
126	    // Draw watermark text as pixel rows across the image.
127	    // We render the text as a simple rasterized banner at the bottom of the image.
128	    let font_height = std::cmp::max(14, h / 30) as usize;
129	    let text_bytes = watermark.as_bytes();
130	    let banner_h = font_height + 8;
131	    let y_start = if (h as usize) > banner_h { h as usize - banner_h } else { 0 };
132	
133	    // Draw semi-transparent dark banner across the bottom
134	    for y in y_start..(h as usize) {
135	        for x in 0..(w as usize) {
136	            let px = overlay.get_pixel_mut(x as u32, y as u32);
137	            // Blend with dark semi-transparent overlay (alpha ~60%)
138	            px[0] = ((px[0] as u16 * 100) / 255) as u8;
139	            px[1] = ((px[1] as u16 * 100) / 255) as u8;
140	            px[2] = ((px[2] as u16 * 100) / 255) as u8;
141	        }
142	    }
143	
144	    // Render each character of the watermark as a 5x7 monospace pixel font
145	    let char_w = 6usize;
146	    let char_h = std::cmp::min(7, font_height);
147	    let text_y = y_start + 4;
148	    let max_chars = (w as usize) / char_w;
149	    let display_text: String = watermark.chars().take(max_chars).collect();
150	
151	    for (ci, ch) in display_text.chars().enumerate() {
152	        let glyph = simple_glyph(ch);
153	        let x_off = 4 + ci * char_w;
154	        for gy in 0..char_h {
155	            for gx in 0..5 {
156	                if glyph[gy % 7] & (1 << (4 - gx)) != 0 {
157	                    let px = x_off + gx;
158	                    let py = text_y + gy;
159	                    if px < w as usize && py < h as usize {
160	                        overlay.put_pixel(px as u32, py as u32, Rgba([255, 255, 255, 230]));
161	                    }
162	                }
163	            }
164	        }
165	    }
166	
167	    // Encode back
168	    let mut buf = std::io::Cursor::new(Vec::new());
169	    if overlay.write_to(&mut buf, output_format).is_ok() {
170	        buf.into_inner()
171	    } else {
172	        img_bytes.to_vec()
173	    }
174	}
