52	/// PDF: Append a watermark page with the text rendered as a content stream.
53	fn embed_watermark_pdf(pdf_bytes: &[u8], watermark: &str) -> Vec<u8> {
54	    // Strategy: append new objects after %%EOF, adding a visible text page.
55	    // This is a standards-compliant incremental update that any PDF reader renders.
56	    let mut output = pdf_bytes.to_vec();
57	
58	    // Find the highest object number (rough parse)
59	    let pdf_str = String::from_utf8_lossy(pdf_bytes);
60	    let mut max_obj: u32 = 10;
61	    for line in pdf_str.lines() {
62	        if let Some(pos) = line.find(" 0 obj") {
63	            if let Ok(n) = line[..pos].trim().parse::<u32>() {
64	                if n > max_obj { max_obj = n; }
65	            }
66	        }
67	    }
68	
69	    let page_obj = max_obj + 1;
70	    let content_obj = max_obj + 2;

