314	/// Guard: redirects to /login if user is not authenticated.
315	fn require_auth() -> Option<services::auth::UserInfo> {
316	    let user = services::auth::get_current_user();
317	    if user.is_none() {
318	        if let Some(window) = web_sys::window() {
319	            let _ = window.location().set_href("/login");
320	        }
321	    }
322	    user
323	}
324	
325	/// Guard: redirects to /login if user is not an administrator.
326	fn require_admin() -> Option<services::auth::UserInfo> {
327	    let user = require_auth()?;
328	    if user.role != "administrator" {
329	        if let Some(window) = web_sys::window() {
330	            let _ = window.location().set_href("/dashboard");
331	        }
332	        return None;
333	    }
334	    Some(user)
335	}
336	
337	/// Guard: redirects to /dashboard if user is not staff or administrator.
338	fn require_staff() -> Option<services::auth::UserInfo> {
339	    let user = require_auth()?;
340	    if user.role != "administrator" && user.role != "academic_staff" {
341	        if let Some(window) = web_sys::window() {
342	            let _ = window.location().set_href("/dashboard");
343	        }
344	        return None;
345	    }
346	    Some(user)
347	}
