1	use crate::middleware::AuthenticatedUser;
2	use crate::models::submission::*;
3	use crate::models::{self, content};
4	use crate::DbPool;
5	use base64::Engine;
6	use rocket::http::{ContentType, Header, Status};
7	use rocket::serde::json::Json;
8	use rocket::State;
9	use sha2::{Digest, Sha256};
10	use uuid::Uuid;
11	
12	/// Newtype wrapper returning the watermarked file as a direct download
13	/// (not a ZIP bundle — the watermark is embedded in the file itself).
14	struct FileDownload {
15	    filename: String,
16	    content_type: String,
17	    watermark: String,
18	    watermark_hash: String,
19	    body: Vec<u8>,
20	}
21	
22	impl<'r> rocket::response::Responder<'r, 'static> for FileDownload {
23	    fn respond_to(self, _: &'r rocket::Request<'_>) -> rocket::response::Result<'static> {
24	        let disposition = format!("attachment; filename=\"{}\"", self.filename);
25	        let (top, sub) = self.content_type.split_once('/').unwrap_or(("application", "octet-stream"));
26	        rocket::response::Response::build()
27	            .status(Status::Ok)
28	            .header(ContentType::new(top.to_string(), sub.to_string()))
29	            .header(Header::new("Content-Disposition", disposition))
30	            .header(Header::new("X-Watermark", self.watermark))
31	            .header(Header::new("X-Watermark-Hash", self.watermark_hash))
32	            .sized_body(self.body.len(), std::io::Cursor::new(self.body))
33	            .ok()
34	    }
35	}
36	
37	/// Embed a visible watermark directly into the file bytes.
38	/// - PDF: appends an incremental update with a new content-stream page containing visible watermark text
39	/// - DOCX: injects a visible red italic watermark paragraph at the top of word/document.xml body
40	/// - PNG: decodes the image, renders a visible text banner at the bottom of the pixels, re-encodes as PNG
