fn embed_watermark_pdf(pdf_bytes: &[u8], watermark: &str) -> Vec<u8> {
    // Strategy: append new objects after %%EOF via a standards-compliant
    // incremental update.  We add a new Page, content stream, and font
    // object and reference the *real* Pages (catalog root) object instead
    // of assuming it is always object 1.
    let mut output = pdf_bytes.to_vec();
    let pdf_str = String::from_utf8_lossy(pdf_bytes);

    // --- Robust object-number scan using regex-like match on "N 0 obj" ---
    let mut max_obj: u32 = 0;
    for line in pdf_str.lines() {
        let trimmed = line.trim();
        if let Some(pos) = trimmed.find(" 0 obj") {
            if let Ok(n) = trimmed[..pos].parse::<u32>() {
                if n > max_obj { max_obj = n; }
            }
        }
    }
    // Fallback: if we somehow found nothing, start above a safe minimum
    if max_obj == 0 { max_obj = 20; }

    // --- Find the actual /Pages object number for /Parent reference ---
    // Look for /Type /Pages in the PDF text and extract its object number.
    let pages_obj_ref = find_pages_object(&pdf_str).unwrap_or_else(|| "1 0 R".to_string());

    let page_obj = max_obj + 1;
    let content_obj = max_obj + 2;
    let font_obj = max_obj + 3;

    // Escape watermark for PDF text operators
    let safe_wm = watermark.replace('\\', "\\\\").replace('(', "\\(").replace(')', "\\)");
    let lines: Vec<&str> = safe_wm.split('|').map(|s| s.trim()).collect();
    let mut text_ops = String::new();
    text_ops.push_str("BT\n/F1 10 Tf\n50 750 Td\n14 TL\n");
    for line in &lines {
        text_ops.push_str(&format!("({}) Tj T*\n", line));
    }
    text_ops.push_str("(---) Tj T*\n(WATERMARKED DOCUMENT - Meridian Academic Portal) Tj\nET\n");

    let content_stream = text_ops.as_bytes();
    let content_len = content_stream.len();

    // --- Locate previous startxref for the trailer /Prev entry ---
    let prev_startxref = pdf_str
        .rfind("startxref")
        .and_then(|pos| {
            pdf_str[pos + 9..].trim().lines().next()
                .and_then(|l| l.trim().parse::<usize>().ok())
        })
        .unwrap_or(0);

    // --- Build incremental update, recording real byte offsets ---
    output.push(b'\n');

    let page_obj_offset = output.len();
    let page_obj_str = format!(
        "{page_obj} 0 obj\n<< /Type /Page /Parent {parent} /MediaBox [0 0 612 792] /Contents {content_obj} 0 R /Resources << /Font << /F1 {font_obj} 0 R >> >> >>\nendobj\n",
        page_obj = page_obj, parent = pages_obj_ref,
        content_obj = content_obj, font_obj = font_obj
    );
    output.extend_from_slice(page_obj_str.as_bytes());

    let content_obj_offset = output.len();
    let content_obj_str = format!(
        "{content_obj} 0 obj\n<< /Length {content_len} >>\nstream\n{text_ops}endstream\nendobj\n",
        content_obj = content_obj, content_len = content_len,
        text_ops = String::from_utf8_lossy(content_stream)
    );
    output.extend_from_slice(content_obj_str.as_bytes());

    let font_obj_offset = output.len();
    let font_obj_str = format!(
        "{font_obj} 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n",
        font_obj = font_obj
    );
    output.extend_from_slice(font_obj_str.as_bytes());

    // --- Xref table with computed positions ---
    let xref_table_offset = output.len();
    let xref_str = format!(
        "xref\n0 1\n0000000000 65535 f \r\n{page_obj} 3\n{page_off:010} 00000 n \r\n{content_off:010} 00000 n \r\n{font_off:010} 00000 n \r\n\
         trailer\n<< /Size {size} /Prev {prev} >>\nstartxref\n{startxref}\n%%EOF\n",
        page_obj = page_obj,
        page_off = page_obj_offset,
        content_off = content_obj_offset,
        font_off = font_obj_offset,
        size = font_obj + 1,
        prev = prev_startxref,
        startxref = xref_table_offset,
    );
    output.extend_from_slice(xref_str.as_bytes());

    output
}

/// Scan the PDF text for the `/Type /Pages` object and return its indirect
/// reference string (e.g. `"3 0 R"`).  Falls back to `None` if the pages
/// catalog cannot be determined.
fn find_pages_object(pdf_str: &str) -> Option<String> {
    // Strategy 1: look for `/Type /Pages` and extract the enclosing object number.
    // The pattern is `N 0 obj ... /Type /Pages ...endobj`.
    // We search backwards from `/Type /Pages` to find the preceding `N 0 obj`.
    if let Some(pages_pos) = pdf_str.find("/Type /Pages") {
        // Walk backwards through newlines to find the "N 0 obj" line
        let before = &pdf_str[..pages_pos];
        for line in before.lines().rev() {
            let trimmed = line.trim();
            if let Some(obj_pos) = trimmed.find(" 0 obj") {
                if let Ok(n) = trimmed[..obj_pos].parse::<u32>() {
                    return Some(format!("{} 0 R", n));
                }
            }
        }
    }

    // Strategy 2: look in the trailer for /Root, then find the Catalog's
    // /Pages entry.
    if let Some(root_pos) = pdf_str.find("/Root") {
        // Extract the object reference after /Root, e.g. "/Root 2 0 R"
        let after_root = &pdf_str[root_pos + 5..];
        let ref_str: String = after_root.chars()
            .skip_while(|c| c.is_whitespace())
            .take_while(|c| c.is_ascii_digit() || *c == ' ' || *c == 'R')
            .collect();
        let ref_str = ref_str.trim();
        // ref_str should be like "2 0 R" — extract obj number
        if let Some(catalog_num) = ref_str.split_whitespace().next().and_then(|s| s.parse::<u32>().ok()) {
            // Find that catalog object and look for /Pages
            let catalog_marker = format!("{} 0 obj", catalog_num);
            if let Some(cat_pos) = pdf_str.find(&catalog_marker) {
                let cat_section = &pdf_str[cat_pos..std::cmp::min(cat_pos + 500, pdf_str.len())];
                if let Some(pages_pos) = cat_section.find("/Pages") {
                    let after_pages = &cat_section[pages_pos + 6..];
                    let pages_ref: String = after_pages.chars()
                        .skip_while(|c| c.is_whitespace())
                        .take_while(|c| c.is_ascii_digit() || *c == ' ' || *c == 'R')
                        .collect();
                    let pages_ref = pages_ref.trim();
                    if pages_ref.ends_with('R') {
                        return Some(pages_ref.to_string());
                    }
                }
            }
        }
    }

    None
}"}

