        // A PNG extension with JPEG magic bytes must be rejected
        let jpeg_magic = [0xFF, 0xD8, 0xFF, 0xE0];
        assert!(models::validate_file_type("image.png", &jpeg_magic).is_err(),
            "Extension/magic mismatch must be rejected");
    }"}

