37	/// Embed a visible watermark directly into the file bytes.
38	/// - PDF: appends an incremental update with a new content-stream page containing visible watermark text
39	/// - DOCX: injects a visible red italic watermark paragraph at the top of word/document.xml body
40	/// - PNG: decodes the image, renders a visible text banner at the bottom of the pixels, re-encodes as PNG
41	/// - JPG: decodes the image, renders a visible text banner at the bottom of the pixels, re-encodes as JPEG
42	fn embed_watermark(file_bytes: &[u8], file_type: &str, watermark_text: &str) -> Vec<u8> {
43	    match file_type {
44	        "pdf" => embed_watermark_pdf(file_bytes, watermark_text),
45	        "docx" => embed_watermark_docx(file_bytes, watermark_text),
46	        "png" => embed_watermark_png(file_bytes, watermark_text),
47	        "jpg" | "jpeg" => embed_watermark_jpg(file_bytes, watermark_text),
48	        _ => file_bytes.to_vec(),
49	    }
50	}

50	}
51	
52	/// PDF: Append a watermark page with the text rendered as a content stream.
53	fn embed_watermark_pdf(pdf_bytes: &[u8], watermark: &str) -> Vec<u8> {
54	    // Strategy: append new objects after %%EOF via a standards-compliant
55	    // incremental update.  We add a new Page, content stream, and font
56	    // object and reference the *real* Pages (catalog root) object instead
57	    // of assuming it is always object 1.
58	    let mut output = pdf_bytes.to_vec();
59	    let pdf_str = String::from_utf8_lossy(pdf_bytes);
60	
61	    // --- Robust object-number scan using regex-like match on "N 0 obj" ---
62	    let mut max_obj: u32 = 0;
63	    for line in pdf_str.lines() {
64	        let trimmed = line.trim();
65	        if let Some(pos) = trimmed.find(" 0 obj") {
66	            if let Ok(n) = trimmed[..pos].parse::<u32>() {
67	                if n > max_obj { max_obj = n; }
68	            }
69	        }
70	    }
71	    // Fallback: if we somehow found nothing, start above a safe minimum
72	    if max_obj == 0 { max_obj = 20; }
73	
74	    // --- Find the actual /Pages object number for /Parent reference ---
75	    // Look for /Type /Pages in the PDF text and extract its object number.
76	    let pages_obj_ref = find_pages_object(&pdf_str).unwrap_or_else(|| "1 0 R".to_string());
77	
78	    let page_obj = max_obj + 1;
79	    let content_obj = max_obj + 2;
80	    let font_obj = max_obj + 3;
81	
82	    // Escape watermark for PDF text operators
83	    let safe_wm = watermark.replace('\\', "\\\\").replace('(', "\\(").replace(')', "\\)");
84	    let lines: Vec<&str> = safe_wm.split('|').map(|s| s.trim()).collect();
85	    let mut text_ops = String::new();
86	    text_ops.push_str("BT\n/F1 10 Tf\n50 750 Td\n14 TL\n");
87	    for line in &lines {
88	        text_ops.push_str(&format!("({}) Tj T*\n", line));
89	    }
90	    text_ops.push_str("(---) Tj T*\n(WATERMARKED DOCUMENT - Meridian Academic Portal) Tj\nET\n");
91	
92	    let content_stream = text_ops.as_bytes();
93	    let content_len = content_stream.len();
94	
95	    // --- Locate previous startxref for the trailer /Prev entry ---
96	    let prev_startxref = pdf_str
97	        .rfind("startxref")
98	        .and_then(|pos| {
99	            pdf_str[pos + 9..].trim().lines().next()
100	                .and_then(|l| l.trim().parse::<usize>().ok())
101	        })
102	        .unwrap_or(0);
103	
104	    // --- Build incremental update, recording real byte offsets ---
105	    output.push(b'\n');
106	
107	    let page_obj_offset = output.len();
108	    let page_obj_str = format!(
109	        "{page_obj} 0 obj\n<< /Type /Page /Parent {parent} /MediaBox [0 0 612 792] /Contents {content_obj} 0 R /Resources << /Font << /F1 {font_obj} 0 R >> >> >>\nendobj\n",
110	        page_obj = page_obj, parent = pages_obj_ref,
111	        content_obj = content_obj, font_obj = font_obj
112	    );
113	    output.extend_from_slice(page_obj_str.as_bytes());
114	
115	    let content_obj_offset = output.len();
116	    let content_obj_str = format!(
117	        "{content_obj} 0 obj\n<< /Length {content_len} >>\nstream\n{text_ops}endstream\nendobj\n",
118	        content_obj = content_obj, content_len = content_len,
119	        text_ops = String::from_utf8_lossy(content_stream)
120	    );
121	    output.extend_from_slice(content_obj_str.as_bytes());
122	
123	    let font_obj_offset = output.len();
124	    let font_obj_str = format!(
125	        "{font_obj} 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n",
126	        font_obj = font_obj
127	    );
128	    output.extend_from_slice(font_obj_str.as_bytes());
129	
130	    // --- Xref table with computed positions ---
131	    let xref_table_offset = output.len();
132	    let xref_str = format!(
133	        "xref\n0 1\n0000000000 65535 f \r\n{page_obj} 3\n{page_off:010} 00000 n \r\n{content_off:010} 00000 n \r\n{font_off:010} 00000 n \r\n\
134	         trailer\n<< /Size {size} /Prev {prev} >>\nstartxref\n{startxref}\n%%EOF\n",
135	        page_obj = page_obj,
136	        page_off = page_obj_offset,
137	        content_off = content_obj_offset,
138	        font_off = font_obj_offset,
139	        size = font_obj + 1,
140	        prev = prev_startxref,
141	        startxref = xref_table_offset,
142	    );
143	    output.extend_from_slice(xref_str.as_bytes());
144	
145	    output
146	}
