148	/// Scan the PDF text for the `/Type /Pages` object and return its indirect
149	/// reference string (e.g. `"3 0 R"`).  Falls back to `None` if the pages
150	/// catalog cannot be determined.
151	fn find_pages_object(pdf_str: &str) -> Option<String> {
152	    // Strategy 1: look for `/Type /Pages` and extract the enclosing object number.
153	    // The pattern is `N 0 obj ... /Type /Pages ...endobj`.
154	    // We search backwards from `/Type /Pages` to find the preceding `N 0 obj`.
155	    if let Some(pages_pos) = pdf_str.find("/Type /Pages") {
156	        // Walk backwards through newlines to find the "N 0 obj" line
157	        let before = &pdf_str[..pages_pos];
158	        for line in before.lines().rev() {
159	            let trimmed = line.trim();
160	            if let Some(obj_pos) = trimmed.find(" 0 obj") {
161	                if let Ok(n) = trimmed[..obj_pos].parse::<u32>() {
162	                    return Some(format!("{} 0 R", n));
163	                }
164	            }
165	        }
166	    }
167	
168	    // Strategy 2: look in the trailer for /Root, then find the Catalog's
169	    // /Pages entry.
170	    if let Some(root_pos) = pdf_str.find("/Root") {
171	        // Extract the object reference after /Root, e.g. "/Root 2 0 R"
172	        let after_root = &pdf_str[root_pos + 5..];
173	        let ref_str: String = after_root.chars()
174	            .skip_while(|c| c.is_whitespace())
175	            .take_while(|c| c.is_ascii_digit() || *c == ' ' || *c == 'R')
176	            .collect();
177	        let ref_str = ref_str.trim();
178	        // ref_str should be like "2 0 R" — extract obj number
179	        if let Some(catalog_num) = ref_str.split_whitespace().next().and_then(|s| s.parse::<u32>().ok()) {
180	            // Find that catalog object and look for /Pages
181	            let catalog_marker = format!("{} 0 obj", catalog_num);
182	            if let Some(cat_pos) = pdf_str.find(&catalog_marker) {
183	                let cat_section = &pdf_str[cat_pos..std::cmp::min(cat_pos + 500, pdf_str.len())];
184	                if let Some(pages_pos) = cat_section.find("/Pages") {
185	                    let after_pages = &cat_section[pages_pos + 6..];
186	                    let pages_ref: String = after_pages.chars()
187	                        .skip_while(|c| c.is_whitespace())
188	                        .take_while(|c| c.is_ascii_digit() || *c == ' ' || *c == 'R')
189	                        .collect();

189	                        .collect();
190	                    let pages_ref = pages_ref.trim();
191	                    if pages_ref.ends_with('R') {
192	                        return Some(pages_ref.to_string());
193	                    }
194	                }
195	            }
196	        }
197	    }
198	
199	    None
200	}
