52	/// PDF: Add a watermark page using the `lopdf` library for correct PDF
53	/// object allocation, page-tree management, xref generation, and
54	/// content-stream construction.  No hand-rolled parsing or heuristic
55	/// byte-offset computation.
56	fn embed_watermark_pdf(pdf_bytes: &[u8], watermark: &str) -> Vec<u8> {
57	    use lopdf::{dictionary, content, Document, Object, Stream, StringFormat};
58	
59	    let mut doc = match Document::load_mem(pdf_bytes) {
60	        Ok(d) => d,
61	        Err(e) => {
62	            log::warn!("lopdf failed to parse PDF for watermarking: {} — returning original", e);
63	            return pdf_bytes.to_vec();
64	        }
65	    };
66	
67	    // --- Build the watermark content stream ---
68	    let safe_wm = watermark.replace('\\', "\\\\").replace('(', "\\(").replace(')', "\\)");
69	    let lines: Vec<&str> = safe_wm.split('|').map(|s| s.trim()).collect();
70	    let mut ops = Vec::new();
71	    ops.push(content::Operation::new("BT", vec![]));
72	    ops.push(content::Operation::new("Tf", vec![Object::Name(b"F1".to_vec()), Object::Real(10.0)]));
73	    ops.push(content::Operation::new("Td", vec![Object::Real(50.0), Object::Real(750.0)]));
74	    ops.push(content::Operation::new("TL", vec![Object::Real(14.0)]));
75	    for line in &lines {
76	        ops.push(content::Operation::new("Tj", vec![Object::String(line.as_bytes().to_vec(), StringFormat::Literal)]));
77	        ops.push(content::Operation::new("T*", vec![]));
78	    }
79	    ops.push(content::Operation::new("Tj", vec![Object::String(b"---".to_vec(), StringFormat::Literal)]));
80	    ops.push(content::Operation::new("T*", vec![]));
81	    ops.push(content::Operation::new("Tj", vec![Object::String(b"WATERMARKED DOCUMENT - Meridian Academic Portal".to_vec(), StringFormat::Literal)]));
82	    ops.push(content::Operation::new("ET", vec![]));
83	
84	    let content_data = content::Content { operations: ops };
85	    let content_bytes = content_data.encode().unwrap_or_default();
86	
87	    // --- Create the content-stream object ---
88	    let content_stream = Stream::new(dictionary! {}, content_bytes);
89	    let content_id = doc.add_object(Object::Stream(content_stream));
90	
91	    // --- Create a Type1 /Helvetica font object ---
92	    let font_id = doc.add_object(dictionary! {
93	        "Type" => Object::Name(b"Font".to_vec()),
94	        "Subtype" => Object::Name(b"Type1".to_vec()),
95	        "BaseFont" => Object::Name(b"Helvetica".to_vec()),
96	    });
97	
98	    // --- Build a Resources dictionary referencing the font ---
99	    let resources = dictionary! {
100	        "Font" => dictionary! {
101	            "F1" => Object::Reference(font_id),
102	        },
103	    };
104	
105	    // --- Find the root Pages object so we can add a kid ---
106	    let pages_id = doc.get_pages().values().next()
107	        .and_then(|first_page_id| {
108	            doc.get_object(*first_page_id).ok()
109	                .and_then(|obj| obj.as_dict().ok())
110	                .and_then(|d| d.get(b"Parent").ok())
111	                .and_then(|p| p.as_reference().ok())
112	        })
113	        .or_else(|| {
114	            // Fallback: walk catalog → /Pages
115	            doc.catalog().ok()
116	                .and_then(|cat| cat.get(b"Pages").ok())
117	                .and_then(|p| p.as_reference().ok())
118	        })
119	        .unwrap_or((1, 0));
120	
121	    // --- Create the new watermark Page ---
122	    let page_dict = dictionary! {
123	        "Type" => Object::Name(b"Page".to_vec()),
124	        "Parent" => Object::Reference(pages_id),
125	        "MediaBox" => Object::Array(vec![Object::Integer(0), Object::Integer(0), Object::Integer(612), Object::Integer(792)]),
126	        "Contents" => Object::Reference(content_id),
127	        "Resources" => resources,
128	    };
129	    let page_id = doc.add_object(page_dict);
130	
131	    // --- Append the new page to the Pages /Kids array and bump /Count ---
132	    if let Ok(pages_obj) = doc.get_object_mut(pages_id) {
133	        if let Ok(pages_dict) = pages_obj.as_dict_mut() {
134	            if let Ok(kids) = pages_dict.get_mut(b"Kids") {
135	                if let Ok(arr) = kids.as_array_mut() {
136	                    arr.push(Object::Reference(page_id));
137	                }
138	            }
139	            if let Ok(count) = pages_dict.get(b"Count") {
140	                if let Ok(n) = count.as_i64() {
141	                    pages_dict.set("Count", Object::Integer(n + 1));
142	                }
143	            }
144	        }
145	    }
